var findLonely = function(nums) {
    const counts = new Map();
    for (const x of nums) {
        counts.set(x, (counts.get(x) || 0) + 1);
    }
    const result = [];
    for (const x of nums) {
        if (counts.get(x) === 1 && !counts.has(x - 1) && !counts.has(x + 1)) {
            result.push(x);
        }
    }
    return result;
